mapper.select:
SELECT id, ncs_code, major_name, middle_name, minor_name, sub_name, unit_count, element_count, min_level, max_level FROM ncs_classification
(sub_name LIKE CONCAT('%', #{q}, '%') OR search_text LIKE CONCAT('%', #{q}, '%'))
ORDER BY (sub_name LIKE CONCAT('%', #{q}, '%')) DESC, element_count DESC LIMIT #{limit}

SELECT id, ncs_code, major_name, middle_name, minor_name, sub_name,
       unit_count, element_count, min_level, max_level
FROM ncs_classification WHERE id = #{id}

SELECT id, cert_type, name, grade, authority, official, has_schedule, SUBSTRING(description, 1, 140) AS description_snippet FROM certificate
cert_type = #{type}
AND (name LIKE CONCAT('%', #{q}, '%') OR search_text LIKE CONCAT('%', #{q}, '%'))
ORDER BY (name LIKE CONCAT('%', #{q}, '%')) DESC, has_schedule DESC, name ASC LIMIT #{limit}

SELECT id, cert_type, name, grade, authority, issuer_org, series, jm_cd, reg_no,
       official, status, description, ncs_sub_name, has_schedule
FROM certificate WHERE id = #{id}
